export function getCryptoHub() {
  return {
    articles: CRYPTO_ARTICLES,
    lessons: CRYPTO_LESSONS,
    glossary: CRYPTO_GLOSSARY,
    strategies: CRYPTO_STRATEGIES,
    stats: {
      articlesCount: CRYPTO_ARTICLES.length,
      lessonsCount: CRYPTO_LESSONS.length,
      glossaryCount: CRYPTO_GLOSSARY.length,
      strategiesCount: CRYPTO_STRATEGIES.length,
    },
  };
}

export function getRelatedCryptoContent(slug: string, type: "article" | "lesson", limit = 3) {
  if (type === "article") {
    const article = CRYPTO_ARTICLES.find((a) => a.slug === slug);
    if (!article) return [];
    return CRYPTO_ARTICLES.filter((a) => a.slug !== slug && a.tags.some((t) => article.tags.includes(t))).slice(0, limit);
  } else {
    const lesson = CRYPTO_LESSONS.find((l) => l.id === slug);
    if (!lesson) return [];
    return CRYPTO_LESSONS.filter((l) => l.id !== slug && l.tags.some((t) => lesson.tags.includes(t))).slice(0, limit);
  }
}
